def answer_question(question):
    """
    Simple FAQ matcher. Returns answer if question matches any key.
    """
    question = question.lower().strip()
    for key, answer in faq.items():
        if key in question or question in key:
            return answer
    
    words = question.split()
    best_match = None
    best_count = 0
    for key in faq:
        count = sum(1 for word in words if word in key and len(word) > 3)
        if count > best_count:
            best_count = count
            best_match = key
    
    if best_match and best_count > 0:
        return faq[best_match]
    
    return "I'm sorry, I don't have an answer for that. Please ask another question about heart disease."